import React, { useState } from 'react';
import { signInWithEmailAndPassword } from 'firebase/auth';
import { doc, getDoc, setDoc, collection, getDocs, query, where } from 'firebase/firestore';
import { auth, db } from '../firebase';
import { Stethoscope, Mail, Lock, Eye, EyeOff } from 'lucide-react';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const uid = userCredential.user.uid;

      // 1. Check by UID
      const adminDoc = await getDoc(doc(db, 'admins', uid));
      if (adminDoc.exists()) {
        // Admin found by UID - proceed
        setLoading(false);
        return;
      }

      // 2. Check by email
      const emailQuery = await getDocs(
        query(collection(db, 'admins'), where('email', '==', email.toLowerCase().trim()))
      );
      if (!emailQuery.empty) {
        // Admin found by email - proceed
        setLoading(false);
        return;
      }

      // 3. If admins collection is completely empty, auto-create first admin
      const allAdmins = await getDocs(collection(db, 'admins'));
      if (allAdmins.empty) {
        await setDoc(doc(db, 'admins', uid), {
          name: userCredential.user.displayName || 'Admin',
          email: email.toLowerCase().trim(),
          role: 'superadmin',
          createdAt: new Date(),
        });
        console.log('First admin account created automatically');
        setLoading(false);
        return;
      }

      // Not an admin
      await auth.signOut();
      setError('Access denied. You are not an admin.');
      setLoading(false);
    } catch (err) {
      console.error('Login error:', err);
      if (err.code === 'auth/user-not-found' || err.code === 'auth/wrong-password' || err.code === 'auth/invalid-credential') {
        setError('Invalid email or password.');
      } else if (err.code === 'auth/too-many-requests') {
        setError('Too many failed attempts. Please try again later.');
      } else {
        setError('Login failed. Please try again.');
      }
      setLoading(false);
    }
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-card-header">
          <div className="login-logo">
            <Stethoscope size={28} color="white" />
          </div>
          <h1>Welcome Back</h1>
          <p>Sign in to Doctor Clinic Admin Panel</p>
        </div>

        {error && <div className="login-error">{error}</div>}

        <form onSubmit={handleLogin}>
          <div className="form-group">
            <label>Email Address</label>
            <div style={{ position: 'relative' }}>
              <Mail size={16} style={{ position: 'absolute', left: 14, top: '50%', transform: 'translateY(-50%)', color: '#8b8b8b' }} />
              <input
                type="email"
                placeholder="admin@doctorclinic.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                style={{ paddingLeft: 40 }}
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label>Password</label>
            <div style={{ position: 'relative' }}>
              <Lock size={16} style={{ position: 'absolute', left: 14, top: '50%', transform: 'translateY(-50%)', color: '#8b8b8b' }} />
              <input
                type={showPassword ? 'text' : 'password'}
                placeholder="Enter your password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                style={{ paddingLeft: 40, paddingRight: 40 }}
                required
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                style={{
                  position: 'absolute', right: 14, top: '50%', transform: 'translateY(-50%)',
                  background: 'none', border: 'none', cursor: 'pointer', color: '#8b8b8b', padding: 0
                }}
              >
                {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>

          <button type="submit" className="login-btn" disabled={loading}>
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
        </form>

        <p style={{ textAlign: 'center', fontSize: 12, color: '#8b8b8b', marginTop: 24 }}>
          Doctor Clinic Admin Panel v1.0
        </p>
      </div>
    </div>
  );
}
